/// initiate heap allocator, frame allocator and kernel space
pub(crate) fn init() {
    heap_allocator::init_heap();
    frame_allocator::init_frame_allocator();
    let kernel_token = KERNEL_SPACE.exclusive_access().token();
    ArchPageTable::activate(ArchPageTable::make_activation(kernel_token, kernel_token));
}

/// Dump allocator statistics for slab and page-table-node cache.
pub(crate) fn dump_allocator_stats() {
    heap_allocator::dump_slab_stats();
    frame_allocator::dump_pt_cache_stats();
    memory_set::dump_pf_profile_stats();
    memory_set::dump_fork_mm_profile_stats();
}

/// Dump allocator statistics with an LTP diagnosis label.
pub(crate) fn dump_allocator_stats_labeled(label: &str) {
    heap_allocator::dump_slab_stats_labeled(label);
    frame_allocator::dump_frame_stats_labeled(label);
    memory_set::dump_shared_mmap_stats_labeled(label);
    kernel_space::dump_kernel_vmap_stack_stats(label);
}

