const FRAME_REF_EVENT_COUNT: usize = 8;
const FRAME_REF_EVENT_FRAME_ALLOC: usize = 1;
const FRAME_REF_EVENT_PT_ALLOC: usize = 2;
const FRAME_REF_EVENT_FRAME_DEC: usize = 3;
const FRAME_REF_EVENT_FRAME_FREE: usize = 4;
const FRAME_REF_EVENT_PT_DEC: usize = 5;
const FRAME_REF_EVENT_PT_FREE: usize = 6;
const FRAME_REF_EVENT_ADD: usize = 7;

#[derive(Clone, Copy)]
struct FrameRefEvent {
    seq: usize,
    kind: usize,
    ppn: usize,
    old: usize,
    new: usize,
}

impl FrameRefEvent {
    const fn empty() -> Self {
        Self {
            seq: 0,
            kind: 0,
            ppn: 0,
            old: 0,
            new: 0,
        }
    }
}

struct FrameRefEvents {
    next_seq: usize,
    events: [FrameRefEvent; FRAME_REF_EVENT_COUNT],
}

impl FrameRefEvents {
    const fn new() -> Self {
        Self {
            next_seq: 1,
            events: [FrameRefEvent::empty(); FRAME_REF_EVENT_COUNT],
        }
    }

    fn record(&mut self, kind: usize, ppn: usize, old: usize, new: usize) {
        let seq = self.next_seq;
        self.next_seq = self.next_seq.wrapping_add(1).max(1);
        self.events[seq % FRAME_REF_EVENT_COUNT] = FrameRefEvent {
            seq,
            kind,
            ppn,
            old,
            new,
        };
    }
}

#[derive(Default)]
struct FrameRefTable {
    base: usize,
    end: usize,
    counts: Vec<usize>,
}

impl FrameRefTable {
    fn init(&mut self, base: PhysPageNum, end: PhysPageNum) {
        self.base = base.0;
        self.end = end.0;
        self.counts.clear();
        self.counts.resize(self.end.saturating_sub(self.base), 0);
    }

    fn index(&self, ppn: PhysPageNum) -> Option<usize> {
        if ppn.0 < self.base || ppn.0 >= self.end {
            return None;
        }
        Some(ppn.0 - self.base)
    }

    fn count(&self, ppn: PhysPageNum) -> usize {
        self.index(ppn)
            .and_then(|idx| self.counts.get(idx).copied())
            .unwrap_or(0)
    }

    fn set_allocated(&mut self, ppn: PhysPageNum, event_kind: usize) {
        let Some(idx) = self.index(ppn) else {
            warn!("[frame-ref] allocated ppn out of range ppn={:#x}", ppn.0);
            return;
        };
        let old = self.counts[idx];
        if old != 0 {
            warn!(
                "[frame-ref] allocated ppn already refcounted ppn={:#x} old={}",
                ppn.0, old
            );
        }
        self.counts[idx] = 1;
        frame_ref_event_record(event_kind, ppn.0, old, 1);
    }

    fn set_range_allocated(&mut self, base_ppn: PhysPageNum, pages: usize) {
        for off in 0..pages {
            self.set_allocated(PhysPageNum(base_ppn.0 + off), FRAME_REF_EVENT_FRAME_ALLOC);
        }
    }

    fn clear_range(&mut self, base_ppn: PhysPageNum, pages: usize) {
        for off in 0..pages {
            let ppn = PhysPageNum(base_ppn.0 + off);
            let Some(idx) = self.index(ppn) else {
                warn!("[frame-ref] drop-range ppn out of range ppn={:#x}", ppn.0);
                continue;
            };
            let old = self.counts[idx];
            if old == 0 {
                warn!("[frame-ref] drop-range zero ref ppn={:#x}", ppn.0);
                continue;
            }
            self.counts[idx] = 0;
            frame_ref_event_record(FRAME_REF_EVENT_FRAME_FREE, ppn.0, old, 0);
        }
    }

    fn dec(&mut self, ppn: PhysPageNum, dec_event: usize, free_event: usize) -> Option<usize> {
        let Some(idx) = self.index(ppn) else {
            warn!("[frame-ref] dealloc ppn out of range ppn={:#x}", ppn.0);
            return None;
        };
        let old = self.counts[idx];
        if old == 0 {
            warn!("[frame-ref] duplicate dealloc ignored ppn={:#x}", ppn.0);
            return None;
        }
        if old > 1 {
            self.counts[idx] = old - 1;
            frame_ref_event_record(dec_event, ppn.0, old, old - 1);
            return Some(old - 1);
        }
        self.counts[idx] = 0;
        frame_ref_event_record(free_event, ppn.0, 1, 0);
        Some(0)
    }

    fn add_ref(&mut self, ppn: PhysPageNum) -> (usize, usize) {
        let Some(idx) = self.index(ppn) else {
            warn!("[frame-ref] add-ref ppn out of range ppn={:#x}", ppn.0);
            return (0, 0);
        };
        let old = self.counts[idx];
        if old == 0 {
            warn!("[frame-ref] add-ref to unallocated ppn={:#x}", ppn.0);
        }
        let new = old.saturating_add(1);
        self.counts[idx] = new;
        frame_ref_event_record(FRAME_REF_EVENT_ADD, ppn.0, old, new);
        (old, new)
    }

    fn stats(&self) -> (usize, usize, usize, usize, usize, [(usize, usize); 4]) {
        let mut refcounted = 0usize;
        let mut ref_eq_1 = 0usize;
        let mut ref_gt_1 = 0usize;
        let mut ref_sum = 0usize;
        let mut ref_max = 0usize;
        let mut samples = [(0usize, 0usize); 4];
        let mut sample_len = 0usize;
        for (idx, &count) in self.counts.iter().enumerate() {
            if count == 0 {
                continue;
            }
            refcounted += 1;
            if count == 1 {
                ref_eq_1 += 1;
            } else {
                ref_gt_1 += 1;
                if sample_len < samples.len() {
                    samples[sample_len] = (self.base + idx, count);
                    sample_len += 1;
                }
            }
            ref_sum = ref_sum.saturating_add(count);
            ref_max = ref_max.max(count);
        }
        if sample_len < samples.len() {
            for (idx, &count) in self.counts.iter().enumerate() {
                if sample_len >= samples.len() {
                    break;
                }
                if count == 1 {
                    samples[sample_len] = (self.base + idx, count);
                    sample_len += 1;
                }
            }
        }
        (refcounted, ref_eq_1, ref_gt_1, ref_sum, ref_max, samples)
    }

    fn high_sample(&self) -> Option<(PhysPageNum, usize)> {
        self.counts
            .iter()
            .enumerate()
            .filter(|(_, count)| **count > 1)
            .max_by_key(|(_, count)| **count)
            .map(|(idx, &count)| (PhysPageNum(self.base + idx), count))
    }
}

