//! Implementation of [`PageTableEntry`] and [`PageTable`].
use super::{
    pt_node_alloc, pt_node_dealloc, FrameTracker, PhysAddr, PhysPageNum, StepByOne, VirtAddr,
    VirtPageNum,
};
use alloc::string::String;
use alloc::vec;
use alloc::vec::Vec;
use bitflags::*;
use hal::pagetable::PageTable as ArchPageTable;

bitflags! {
    /// page table entry flags
    pub(crate) struct PTEFlags: u8 {
        const V = 1 << 0;
        const R = 1 << 1;
        const W = 1 << 2;
        const X = 1 << 3;
        const U = 1 << 4;
        const G = 1 << 5;
        const A = 1 << 6;
        const D = 1 << 7;
    }
}

#[derive(Copy, Clone)]
#[repr(C)]
/// page table entry structure
pub(crate) struct PageTableEntry {
    /// bits of page table entry
    bits: usize,
}

fn pte_cow_bit() -> usize {
    ArchPageTable::pte_sw_cow_bit()
}

fn normalize_leaf_hw_flags(mut flags: PTEFlags) -> PTEFlags {
    if flags.contains(PTEFlags::W) {
        // Sv39 leaf PTEs cannot expose W without R, and writable mappings
        // need D set so stores after mprotect()/fault fill do not refault.
        flags |= PTEFlags::R | PTEFlags::D;
    }
    flags
}

impl PageTableEntry {
    /// Create a new page table entry
    pub(crate) fn new(ppn: PhysPageNum, flags: PTEFlags) -> Self {
        PageTableEntry {
            bits: ArchPageTable::make_pte_bits(
                ppn.0,
                normalize_leaf_hw_flags(flags).bits as usize,
                0,
            ),
        }
    }
    /// Create an empty page table entry
    pub(crate) fn empty() -> Self {
        PageTableEntry { bits: 0 }
    }
    /// Get the physical page number from the page table entry
    pub(crate) fn ppn(&self) -> PhysPageNum {
        ArchPageTable::pte_ppn(self.bits).into()
    }
    /// Get the flags from the page table entry
    pub(crate) fn flags(&self) -> PTEFlags {
        PTEFlags::from_bits(ArchPageTable::pte_flags(self.bits) as u8).unwrap()
    }
    /// Update hardware PTE flags while keeping ppn/software bits.
    pub(crate) fn set_flags(&mut self, flags: PTEFlags) {
        let ppn_bits = self.ppn().0;
        let sw_bits = self.bits & pte_cow_bit();
        self.bits = ArchPageTable::make_pte_bits(
            ppn_bits,
            normalize_leaf_hw_flags(flags).bits as usize,
            sw_bits,
        );
    }
    /// Whether this PTE is marked copy-on-write.
    pub(crate) fn cow(&self) -> bool {
        (self.bits & pte_cow_bit()) != 0
    }
    /// Mark this PTE as copy-on-write in software bit.
    pub(crate) fn set_cow(&mut self, cow: bool) {
        if cow {
            self.bits |= pte_cow_bit();
        } else {
            self.bits &= !pte_cow_bit();
        }
    }
    /// The page pointered by page table entry is valid?
    pub(crate) fn is_valid(&self) -> bool {
        (self.flags() & PTEFlags::V) != PTEFlags::empty()
    }
    /// The page pointered by page table entry is writable?
    pub(crate) fn writable(&self) -> bool {
        (self.flags() & PTEFlags::W) != PTEFlags::empty()
    }
    /// The page pointered by page table entry is executable?
    pub(crate) fn executable(&self) -> bool {
        (self.flags() & PTEFlags::X) != PTEFlags::empty()
    }
}

/// page table structure
pub(crate) struct PageTable {
    root_ppn: PhysPageNum,
    pt_frames: Vec<FrameTracker>,
}

/// Supported leaf page sizes in Sv39 mapping.
#[derive(Copy, Clone, Eq, PartialEq)]
pub(crate) enum PageSizeKind {
    /// 4KiB leaf at L2.
    Size4K,
    /// 2MiB leaf at L1.
    Size2M,
    /// 1GiB leaf at L0.
    Size1G,
}

impl PageSizeKind {
    fn target_level(&self) -> usize {
        match self {
            Self::Size1G => 0,
            Self::Size2M => 1,
            Self::Size4K => 2,
        }
    }
}

/// Assume that it won't oom when creating/mapping.
impl PageTable {
    /// Share kernel high-half root entries from another page table.
    ///
    /// This copies only root-level PTEs and does not take ownership of the
    /// referenced lower-level page-table frames.
    #[cfg(target_arch = "riscv64")]
    pub(crate) fn attach_kernel_root_entries_from(&mut self, kernel: &PageTable) {
        let start = ArchPageTable::pt_entries_per_level() / 2;
        let end = ArchPageTable::pt_entries_per_level().saturating_sub(1);
        let dst = self.root_ppn.get_pte_array();
        let src = kernel.root_ppn.get_pte_array();
        for idx in start..end {
            dst[idx] = src[idx];
        }
    }

    fn walk_leaf(&self, vpn: VirtPageNum) -> Option<(PageTableEntry, usize)> {
        let idxs = vpn.indexes();
        let mut ppn = self.root_ppn;
        for (level, idx) in idxs.iter().enumerate() {
            let pte = ppn.get_pte_array()[*idx];
            if !pte.is_valid() {
                return None;
            }
            let flags = pte.flags();
            if flags.intersects(PTEFlags::R | PTEFlags::W | PTEFlags::X) {
                return Some((pte, level));
            }
            ppn = pte.ppn();
        }
        None
    }

    /// Create a new page table
    pub(crate) fn new() -> Option<Self> {
        let frame = pt_node_alloc()?;
        Some(PageTable {
            root_ppn: frame.ppn,
            pt_frames: vec![frame],
        })
    }
    /// Temporarily used to get arguments from user space.
    pub(crate) fn from_token(satp: usize) -> Self {
        Self {
            root_ppn: PhysPageNum::from(ArchPageTable::token_ppn(satp)),
            pt_frames: Vec::new(),
        }
    }
    /// Find PageTableEntry by VirtPageNum, create a frame for a 4KB page table if not exist
    fn find_pte_create_at_level(
        &mut self,
        vpn: VirtPageNum,
        target_level: usize,
    ) -> Option<&mut PageTableEntry> {
        let idxs = vpn.indexes();
        let mut ppn = self.root_ppn;
        let mut result: Option<&mut PageTableEntry> = None;
        for (i, idx) in idxs.iter().enumerate() {
            let pte = &mut ppn.get_pte_array()[*idx];
            if i == target_level {
                result = Some(pte);
                break;
            }
            if !pte.is_valid() {
                let Some(frame) = pt_node_alloc() else {
                    return None;
                };
                *pte = PageTableEntry::new(frame.ppn, PTEFlags::V);
                self.pt_frames.push(frame);
            }
            ppn = pte.ppn();
        }
        result
    }

    fn find_pte_create(&mut self, vpn: VirtPageNum) -> Option<&mut PageTableEntry> {
        self.find_pte_create_at_level(vpn, ArchPageTable::pt_levels() - 1)
    }

    /// Ensure page-table nodes exist for a 4KiB virtual page without mapping it.
    pub(crate) fn ensure_page_branch(&mut self, vpn: VirtPageNum) {
        let _ = self.find_pte_create(vpn);
    }

    /// Find PageTableEntry by VirtPageNum
    fn find_pte(&self, vpn: VirtPageNum) -> Option<&mut PageTableEntry> {
        let idxs = vpn.indexes();
        let mut ppn = self.root_ppn;
        let mut result: Option<&mut PageTableEntry> = None;
        for (i, idx) in idxs.iter().enumerate() {
