#[cfg(feature = "fork_profile")]
fn fork_prof_delta(start: usize) -> usize {
    get_time().saturating_sub(start)
}

#[cfg(feature = "fork_profile")]
fn fork_prof_add(counter: &AtomicUsize, value: usize) {
    counter.fetch_add(value, Ordering::Relaxed);
}

/// Dump fork profile counters when enabled.
#[cfg(feature = "fork_profile")]
pub(crate) fn dump_fork_profile_stats() {
    let calls = FORK_PROF_CALLS.load(Ordering::Relaxed);
    if calls == 0 {
        return;
    }
    println!(
        "[fork-profile] calls={} sync={} mm={} parent_lock={} trap={} alloc={} fd={} tcb={} attach={} child_trap={}",
        calls,
        FORK_PROF_SYNC_TICKS.load(Ordering::Relaxed),
        FORK_PROF_MM_TICKS.load(Ordering::Relaxed),
        FORK_PROF_PARENT_LOCK_TICKS.load(Ordering::Relaxed),
        FORK_PROF_TRAP_TICKS.load(Ordering::Relaxed),
        FORK_PROF_ALLOC_TICKS.load(Ordering::Relaxed),
        FORK_PROF_FD_TICKS.load(Ordering::Relaxed),
        FORK_PROF_TCB_TICKS.load(Ordering::Relaxed),
        FORK_PROF_ATTACH_TICKS.load(Ordering::Relaxed),
        FORK_PROF_CHILD_TRAP_TICKS.load(Ordering::Relaxed)
    );
}

/// Dump fork profile counters when enabled.
#[cfg(not(feature = "fork_profile"))]
