static TCB_DROPPED: AtomicUsize = AtomicUsize::new(0);
static TCB_DROPPED_ZOMBIE: AtomicUsize = AtomicUsize::new(0);

/// Task control block structure
///
/// Directly save the contents that will not change during running
pub(crate) struct TaskControlBlock {
    // Immutable
    /// Process identifier
    pub pid: PidHandle,
    /// Cached Linux-visible thread-group id for getpid() fast path.
    pub cached_tgid: AtomicUsize,
    /// Cached real parent process id for getppid() fast path.
    pub cached_ppid: AtomicUsize,

    /// Kernel stack corresponding to PID
    pub kernel_stack: KernelStack,

    /// Mutable
    inner: UPSafeCell<TaskControlBlockInner>,
}

impl Drop for TaskControlBlock {
    fn drop(&mut self) {
        TCB_DROPPED.fetch_add(1, Ordering::Relaxed);
        if let Some(inner) = self.try_inner_exclusive_access() {
            let is_zombie = inner.task_status == TaskStatus::Zombie;
            if is_zombie {
                TCB_DROPPED_ZOMBIE.fetch_add(1, Ordering::Relaxed);
            }
            memleak_log!(
                "[ltp-diag] tcb_drop pid={} status={} is_thread={} vm_owner={} mm_refs={} fd_open={} children={}",
                self.pid.0,
                inner.task_status.diag_name(),
                inner.is_thread as usize,
                inner.vm_owner_pid,
                Arc::strong_count(&inner.mm),
                inner.fd_table.iter().filter(|fd| fd.is_some()).count(),
                inner.children.len(),
            );
        } else {
            memleak_log!("[ltp-diag] tcb_drop pid={} status=locked", self.pid.0);
        }
    }
}

pub(crate) fn task_drop_diag_stats() -> (usize, usize) {
    (
        TCB_DROPPED.load(Ordering::Relaxed),
        TCB_DROPPED_ZOMBIE.load(Ordering::Relaxed),
    )
}

