//!Implementation of [`TaskManager`]
use super::TaskControlBlock;
use crate::processor::coroutine::CoroutineUnit;
use crate::sync::UPSafeCell;
use alloc::collections::VecDeque;
use alloc::sync::Arc;
use lazy_static::*;
///A array of `TaskControlBlock` that is thread-safe
pub(crate) struct TaskManager {
    ready_queue: VecDeque<CoroutineUnit>,
}

/// A priority-aware scheduler (higher `priority` first).
impl TaskManager {
    ///Creat an empty TaskManager
    pub(crate) fn new() -> Self {
        Self {
            ready_queue: VecDeque::new(),
        }
    }
    /// Add process back to ready queue
    pub(crate) fn add(&mut self, task: Arc<TaskControlBlock>) {
        self.ready_queue.push_back(CoroutineUnit::new(task));
    }
    /// Take a process out of the ready queue
    pub(crate) fn fetch(&mut self) -> Option<Arc<TaskControlBlock>> {
        loop {
            if self.ready_queue.is_empty() {
                return None;
            }
            let mut best_idx = 0usize;
            let mut best_prio = self
                .ready_queue
                .front()
                .map(|unit| unit.priority())
                .unwrap_or(isize::MIN);
            for (idx, unit) in self.ready_queue.iter().enumerate().skip(1) {
                let prio = unit.priority();
                if prio > best_prio {
                    best_prio = prio;
                    best_idx = idx;
                }
            }
            let unit = if best_idx == 0 {
                self.ready_queue.pop_front()
            } else {
                self.ready_queue.remove(best_idx)
            };
            let Some(unit) = unit else {
                continue;
            };
            let task = unit.into_task();
            if matches!(
                task.inner_exclusive_access().task_status,
                super::TaskStatus::Sleeping | super::TaskStatus::Zombie
            ) {
                continue;
            }
            return Some(task);
        }
    }
}

lazy_static! {
    /// TASK_MANAGER instance through lazy_static!
    pub(crate) static ref TASK_MANAGER: UPSafeCell<TaskManager> =
        unsafe { UPSafeCell::new(TaskManager::new()) };
}

/// Add process to ready queue
pub(crate) fn add_task(task: Arc<TaskControlBlock>) {
    //trace!("kernel: TaskManager::add_task");
    TASK_MANAGER.exclusive_access().add(task);
}

/// Take a process out of the ready queue
pub(crate) fn fetch_task() -> Option<Arc<TaskControlBlock>> {
    //trace!("kernel: TaskManager::fetch_task");
    TASK_MANAGER.exclusive_access().fetch()
}

/// Return the global manager queue length for leak diagnostics.
pub(crate) fn ready_queue_len() -> usize {
    TASK_MANAGER.exclusive_access().ready_queue.len()
}

/// Return whether the global ready queue holds a task pid for leak diagnostics.
pub(crate) fn ready_queue_contains_pid(pid: usize) -> bool {
    TASK_MANAGER
        .exclusive_access()
        .ready_queue
        .iter()
        .any(|unit| unit.task_pid() == pid)
}

/// Return how many global ready queue entries hold a task pid for leak diagnostics.
pub(crate) fn ready_queue_pid_count(pid: usize) -> usize {
    TASK_MANAGER
        .exclusive_access()
        .ready_queue
        .iter()
        .filter(|unit| unit.task_pid() == pid)
        .count()
}

