/// trait File for all file types
pub(crate) trait File: Send + Sync {
    /// the file readable?
    fn readable(&self) -> bool;
    /// the file writable?
    fn writable(&self) -> bool;
    /// read from the file to buf, return the number of bytes read
    fn read(&self, buf: UserBuffer) -> usize;
    /// write to the file from buf, return the number of bytes written
    fn write(&self, buf: UserBuffer) -> usize;
    /// seek current offset, return new offset
    fn seek(&self, _offset: isize, _whence: usize) -> Option<usize> {
        None
    }
    /// get current file offset
    fn offset(&self) -> Option<usize> {
        None
    }
    /// set current file offset
    fn set_offset(&self, _offset: usize) {}
    /// read from an explicit file offset without changing the shared file offset
    fn read_at(&self, _offset: usize, _buf: UserBuffer) -> Option<usize> {
        None
    }
    /// write to an explicit file offset without changing the shared file offset
    fn write_at(&self, _offset: usize, _buf: UserBuffer) -> Option<usize> {
        None
    }

    /// Called when this file handle is duplicated (fork/dup/fcntl dup).
    fn on_dup(&self) {}
    /// Called when one file descriptor reference to this handle is closed.
    fn on_close(&self) {}
    /// Flush buffered file data owned by this open file object.
    fn flush(&self) -> bool {
        true
    }
    /// absolute path this file opened from
    fn path(&self) -> Option<alloc::string::String> {
        None
    }
    /// real storage path used by backing I/O, if different from display path
    fn storage_path(&self) -> Option<alloc::string::String> {
        self.path()
    }
    /// query file status
    fn stat(&self) -> Option<Stat> {
        None
    }

    /// Cheap file-type hint for hot syscall paths that only need broad shape.
    fn stat_mode_hint(&self) -> Option<StatMode> {
        None
    }

    /// Unique open-file-description ID shared by dup/fork copies.
    fn description_id(&self) -> Option<u64> {
        None
    }

    /// Whether this file descriptor is an O_PATH-like handle.
    fn is_path_only(&self) -> bool {
        false
    }

    /// Whether epoll can monitor this file description.
    fn poll_supports_epoll(&self) -> bool {
        false
    }

    /// Read readiness for select/poll/epoll.
    fn poll_readable(&self) -> bool {
        self.readable()
    }

    /// Priority readiness for select/poll/epoll.
    fn poll_priority(&self) -> bool {
        false
    }

    /// Write readiness for select/poll/epoll.
    fn poll_writable(&self) -> bool {
        self.writable()
    }

    /// Error condition for poll/epoll.
    fn poll_error(&self) -> bool {
        false
    }

    /// Hangup condition for poll/epoll.
    fn poll_hup(&self) -> bool {
        false
    }

    /// Read-half hangup condition for epoll.
    fn poll_rdhup(&self) -> bool {
        false
    }

    /// downcast support for special file types (e.g. socket)
    fn as_any(&self) -> &dyn Any;
}

pub(crate) fn exec_write_open_inc(path: &str) {
    let mut refs = EXEC_WRITE_OPEN_REFS.exclusive_access();
    let entry = refs.entry(path.into()).or_insert(0);
    *entry = entry.saturating_add(1);
}

pub(crate) fn exec_write_open_dec(path: &str) {
    let mut refs = EXEC_WRITE_OPEN_REFS.exclusive_access();
    let Some(count) = refs.get_mut(path) else {
        return;
    };
    if *count > 1 {
        *count -= 1;
    } else {
        refs.remove(path);
    }
}

pub(crate) fn exec_write_open_count(path: &str) -> usize {
    EXEC_WRITE_OPEN_REFS
        .exclusive_access()
        .get(path)
        .copied()
        .unwrap_or(0)
}

pub(crate) fn exec_write_open_under(path: &str) -> bool {
    EXEC_WRITE_OPEN_REFS
        .exclusive_access()
        .iter()
        .any(|(entry, count)| {
            *count != 0
                && (entry == path
                    || (entry.starts_with(path)
                        && entry.as_bytes().get(path.len()).copied() == Some(b'/')))
        })
}

