pub(crate) fn flock_try_lock(path: &str, owner: u64, operation: i32) -> Result<bool, isize> {
    const LOCK_SH: i32 = 1;
    const LOCK_EX: i32 = 2;
    const LOCK_NB: i32 = 4;
    const LOCK_UN: i32 = 8;
    const EINVAL: isize = -22;

    let base = operation & (LOCK_SH | LOCK_EX | LOCK_UN);
    if base == 0 || (base & (base - 1)) != 0 {
        return Err(EINVAL);
    }
    if (operation & !(LOCK_SH | LOCK_EX | LOCK_NB | LOCK_UN)) != 0 {
        return Err(EINVAL);
    }

    let mut map = FLOCK_REFS.exclusive_access();
    let mut remove_entry = false;
    let result = {
        let state = map.entry(path.into()).or_insert_with(FlockState::new);
        match base {
            LOCK_UN => {
                state.shared.remove(&owner);
                if state.exclusive == Some(owner) {
                    state.exclusive = None;
                }
                remove_entry = state.shared.is_empty() && state.exclusive.is_none();
                Ok(true)
            }
            LOCK_SH => {
                if matches!(state.exclusive, Some(holder) if holder != owner) {
                    return Ok(false);
                }
                state.exclusive = None;
                state.shared.insert(owner);
                Ok(true)
            }
            LOCK_EX => {
                let only_self_shared = state.shared.is_empty()
                    || (state.shared.len() == 1 && state.shared.contains(&owner));
                if matches!(state.exclusive, Some(holder) if holder != owner) || !only_self_shared {
                    return Ok(false);
                }
                state.shared.remove(&owner);
                state.exclusive = Some(owner);
                Ok(true)
            }
            _ => Err(EINVAL),
        }
    };
    if remove_entry {
        map.remove(path);
    }
    result
}

pub(crate) fn flock_release(path: &str, owner: u64) {
    let mut map = FLOCK_REFS.exclusive_access();
    let remove_entry = {
        let Some(state) = map.get_mut(path) else {
            return;
        };
        state.shared.remove(&owner);
        if state.exclusive == Some(owner) {
            state.exclusive = None;
        }
        state.shared.is_empty() && state.exclusive.is_none()
    };
    if remove_entry {
        map.remove(path);
    }
}

