fn ltp_exec_diag_interesting(path: &str, args: &[alloc::string::String]) -> bool {
    path.ends_with("/execve05")
        || path.ends_with("/execve_child")
        || args
            .iter()
            .any(|arg| arg.as_str() == "execve_child" || arg.as_str() == "canary")
}

fn ltp_exec_diag_env_path<'a>(envs: &'a [alloc::string::String]) -> &'a str {
    envs.iter()
        .find_map(|env| env.strip_prefix("LTP_IPC_PATH="))
        .unwrap_or("")
}

fn ltp_exec_diag_log(
    stage: &str,
    pid: usize,
    raw_path: &str,
    path: &str,
    args: &[alloc::string::String],
    envs: &[alloc::string::String],
    image_len: usize,
    ret: isize,
) {
    if !ltp_exec_diag_interesting(path, args) {
        return;
    }
    let seq = LTP_EXEC_DIAG_COUNT.fetch_add(1, Ordering::Relaxed);
    if seq >= 64 && seq % 256 != 0 {
        return;
    }
    crate::memleak_log!(
        "[ltp-diag] exec_probe seq={} stage={} pid={} raw={} path={} argv0={} argv1={} argc={} envc={} ltp_ipc={} tmp={} ext={} image_len={} ret={}",
        seq,
        stage,
        pid,
        raw_path,
        path,
        args.get(0).map(|s| s.as_str()).unwrap_or(""),
        args.get(1).map(|s| s.as_str()).unwrap_or(""),
        args.len(),
        envs.len(),
        ltp_exec_diag_env_path(envs),
        tmp_ram_file_exists(path) as usize,
        ext4_exists(path) as usize,
        image_len,
        ret,
    );
}

