fn total_iov_len(out: &[&mut [u8]]) -> usize {
    out.iter()
        .fold(0usize, |acc, seg| acc.saturating_add(seg.len()))
}

fn copy_into_iov(
    out: &mut [&mut [u8]],
    mut seg_idx: usize,
    mut seg_off: usize,
    src: &[u8],
) -> (usize, usize, usize) {
    let mut copied = 0usize;
    while copied < src.len() && seg_idx < out.len() {
        let seg = &mut out[seg_idx];
        if seg_off >= seg.len() {
            seg_idx += 1;
            seg_off = 0;
            continue;
        }
        let room = seg.len() - seg_off;
        let n = core::cmp::min(room, src.len() - copied);
        seg[seg_off..seg_off + n].copy_from_slice(&src[copied..copied + n]);
        copied += n;
        seg_off += n;
        if seg_off == seg.len() {
            seg_idx += 1;
            seg_off = 0;
        }
    }
    (copied, seg_idx, seg_off)
}

fn copy_from_iov(iov: &[&[u8]], dst: &mut [u8]) -> usize {
    let mut copied = 0usize;
    for seg in iov.iter() {
        if copied >= dst.len() {
            break;
        }
        let n = core::cmp::min(seg.len(), dst.len() - copied);
        dst[copied..copied + n].copy_from_slice(&seg[..n]);
        copied += n;
    }
    copied
}

fn append_pod<T: Copy>(out: &mut Vec<u8>, value: &T) {
    let raw = unsafe {
        core::slice::from_raw_parts((value as *const T) as *const u8, core::mem::size_of::<T>())
    };
    out.extend_from_slice(raw);
}

fn align4(len: usize) -> usize {
    (len + 3) & !3
}

