//! Coroutine scheduling unit.
//!
//! Scheduler operates on `CoroutineUnit` instead of directly on process objects.

use crate::mission::{TaskControlBlock, TaskStatus};
use alloc::sync::Arc;
use core::future::Future;
use core::pin::Pin;
use core::sync::atomic::{AtomicUsize, Ordering};
use core::task::{Context, Poll};

static NEXT_COROUTINE_ID: AtomicUsize = AtomicUsize::new(1);
static COROUTINE_CREATED: AtomicUsize = AtomicUsize::new(0);
static COROUTINE_COMPLETED: AtomicUsize = AtomicUsize::new(0);
static COROUTINE_DROPPED: AtomicUsize = AtomicUsize::new(0);
static COROUTINE_DROPPED_COMPLETED: AtomicUsize = AtomicUsize::new(0);

#[derive(Copy, Clone, Eq, PartialEq)]
/// Lifecycle state of a coroutine unit.
pub(crate) enum CoroutineState {
    /// waiting in run queue
    Ready,
    /// selected by scheduler and about to run
    Running,
    /// consumed / finished unit
    Completed,
}

/// A coroutine scheduling unit that wraps one runnable process task.
pub(crate) struct CoroutineUnit {
    id: usize,
    state: CoroutineState,
    priority: isize,
    task: Option<Arc<TaskControlBlock>>,
}

impl CoroutineUnit {
    /// Create a new coroutine unit from a process task.
    pub(crate) fn new(task: Arc<TaskControlBlock>) -> Self {
        COROUTINE_CREATED.fetch_add(1, Ordering::Relaxed);
        let priority = task.priority();
        Self {
            id: NEXT_COROUTINE_ID.fetch_add(1, Ordering::Relaxed),
            state: CoroutineState::Ready,
            priority,
            task: Some(task),
        }
    }

    /// Get coroutine id.
    pub(crate) fn id(&self) -> usize {
        self.id
    }

    /// Mark unit running.
    pub(crate) fn mark_running(&mut self) {
        self.state = CoroutineState::Running;
    }

    /// Mark unit ready again.
    pub(crate) fn mark_ready(&mut self) {
        self.state = CoroutineState::Ready;
    }

    /// Mark unit completed.
    pub(crate) fn mark_completed(&mut self) {
        if self.state != CoroutineState::Completed {
            COROUTINE_COMPLETED.fetch_add(1, Ordering::Relaxed);
        }
        self.state = CoroutineState::Completed;
    }

    /// Get the process priority used by scheduler.
    pub(crate) fn priority(&self) -> isize {
        self.priority
    }

    /// Return wrapped task pid for leak diagnostics.
    pub(crate) fn task_pid(&self) -> usize {
        self.task.as_ref().map(|task| task.pid.0).unwrap_or(0)
    }

    /// Consume this unit and return inner task.
    pub(crate) fn into_task(mut self) -> Arc<TaskControlBlock> {
        self.mark_completed();
        self.task.take().expect("CoroutineUnit task already taken")
    }
}

impl Drop for CoroutineUnit {
    fn drop(&mut self) {
        if let Some(task) = self.task.as_ref() {
            let task_status = task.inner_exclusive_access().task_status;
            crate::memleak_log!(
                "[ltp-diag] co_drop id={} pid={} state={} task_status={} strong_before_drop={}",
                self.id,
                task.pid.0,
                self.state.diag_name(),
                task_status.diag_name(),
                Arc::strong_count(task),
            );
        } else {
            crate::memleak_log!(
                "[ltp-diag] co_drop id={} pid=0 state={} task_status=taken strong_before_drop=0",
                self.id,
                self.state.diag_name(),
            );
        }
        COROUTINE_DROPPED.fetch_add(1, Ordering::Relaxed);
        if self.state == CoroutineState::Completed {
            COROUTINE_DROPPED_COMPLETED.fetch_add(1, Ordering::Relaxed);
        }
    }
}

/// Return coroutine lifetime counters for leak diagnostics.
pub(crate) fn coroutine_diag_stats() -> (usize, usize, usize, usize) {
    (
        COROUTINE_CREATED.load(Ordering::Relaxed),
        COROUTINE_COMPLETED.load(Ordering::Relaxed),
        COROUTINE_DROPPED.load(Ordering::Relaxed),
        COROUTINE_DROPPED_COMPLETED.load(Ordering::Relaxed),
    )
}

impl Future for CoroutineUnit {
    type Output = usize;

    fn poll(mut self: Pin<&mut Self>, cx: &mut Context<'_>) -> Poll<Self::Output> {
        self.mark_running();
        let task = self
            .task
            .as_ref()
            .expect("CoroutineUnit task missing during poll")
            .clone();
        let sleep_sequence = task.sleep_sequence();
        super::processor::run_one_task_slice(task);
        let task = self
            .task
            .as_ref()
            .expect("CoroutineUnit task missing after poll");
        let status = task.inner_exclusive_access().task_status;
        let sleep_sequence_changed = task.sleep_sequence() != sleep_sequence;
        if sleep_sequence_changed
            || matches!(
                status,
                TaskStatus::Sleeping | TaskStatus::Waking | TaskStatus::Zombie
            )
        {
            crate::memleak_log!(
                "[ltp-diag] co_complete id={} pid={} task_status={} sleep_seq_changed={} strong_before_complete={}",
                self.id(),
                task.pid.0,
                status.diag_name(),
                sleep_sequence_changed as usize,
                Arc::strong_count(&task),
            );
            self.mark_completed();
            Poll::Ready(self.id())
        } else {
            self.mark_ready();
            // cooperative reschedule: keep this coroutine runnable in executor loop
            cx.waker().wake_by_ref();
            Poll::Pending
        }
    }
}

impl CoroutineState {
    fn diag_name(self) -> &'static str {
        match self {
            Self::Ready => "ready",
            Self::Running => "running",
            Self::Completed => "completed",
        }
    }
}

