/// Per-CPU load tracker.
pub(crate) struct TaskLoadTracker {
    /// Last update timestamp in us.
    pub(crate) last_update_time: u64,
    /// Decayed accumulated load.
    pub(crate) load_sum: u64,
    /// Contribution inside current 1024us window.
    pub(crate) period_contribute: u32,
    /// Exposed average load.
    pub(crate) load_avg: u32,
}

impl TaskLoadTracker {
    /// Create a zeroed tracker.
    pub(crate) const fn new() -> Self {
        Self {
            last_update_time: 0,
            load_sum: 0,
            period_contribute: 0,
            load_avg: 0,
        }
    }

    /// Update tracker on scheduling events (enqueue/dequeue).
    pub(crate) fn update_on_event(&mut self, now_us: u64, queue_depth: u32) {
        self.update_load_sum(now_us, queue_depth);
        self.update_load_avg();
    }

    /// Update tracker on runtime accounting.
    pub(crate) fn update_runtime(&mut self, delta_us: u64) {
        if delta_us == 0 {
            return;
        }
        self.load_sum = self.load_sum.saturating_add(delta_us);
        self.update_load_avg();
    }

    fn get_pelt_divider(&self) -> u32 {
        self.period_contribute + PELT_MIN_DIVIDER
    }

    fn update_load_avg(&mut self) {
        let divider = self.get_pelt_divider() as u64;
        self.load_avg = (self.load_sum / divider) as u32;
    }

    fn update_load_sum(&mut self, now_us: u64, queue_depth: u32) {
        if self.last_update_time == 0 {
            self.last_update_time = now_us;
            return;
        }
        let mut delta = now_us.wrapping_sub(self.last_update_time);
        if delta == 0 {
            return;
        }
        self.last_update_time = now_us;
        delta += self.period_contribute as u64;

        let periods = delta / 1024;
        if periods != 0 {
            self.load_sum = decay_load(self.load_sum, periods);
            delta %= 1024;
            let add = add_segment(periods, 1024 - self.period_contribute, delta as u32);
            self.load_sum = self
                .load_sum
                .saturating_add(add as u64)
                .saturating_add(queue_depth as u64);
        } else {
            self.load_sum = self.load_sum.saturating_add(queue_depth as u64);
        }
        self.period_contribute = delta as u32;
    }
}

fn decay_load(mut val: u64, num: u64) -> u64 {
    if num > LOAD_AVG_PERIOD as u64 * 63 {
        return 0;
    }
    let mut inner_num = num as u32;
    if inner_num >= LOAD_AVG_PERIOD {
        let shift = inner_num / LOAD_AVG_PERIOD;
        val >>= shift;
        inner_num %= LOAD_AVG_PERIOD;
    }
    let factor = DECLINE_TABLE[inner_num as usize];
    ((val as u128 * factor as u128) >> 32) as u64
}

fn add_segment(period_num: u64, load1: u32, load3: u32) -> u32 {
    let c1 = decay_load(load1 as u64, period_num);
    let c2 = LOAD_AVG_MAX as u64 - decay_load(LOAD_AVG_MAX as u64, period_num) - 1024;
    let c3 = load3 as u64;
    (c1 + c2 + c3) as u32
}

/// Round-robin queue selection when a new task enters system.
pub(crate) fn select_run_queue_index(cpu_count: usize, next: &AtomicUsize) -> usize {
    next.fetch_add(1, Ordering::SeqCst) % cpu_count
}

/// Global load balancing: migrate one task when imbalance exceeds threshold.
pub(crate) fn load_balance() -> bool {
    let ncpu = processor_count();
    if ncpu <= 1 {
        return true;
    }

    let mut busiest = 0usize;
    let mut idlest = 0usize;
    let mut max_load = 0u32;
    let mut min_load = u32::MAX;

    for cpu in 0..ncpu {
        let l = cpu_load_avg(cpu);
        if l > max_load {
            max_load = l;
            busiest = cpu;
        }
        if l < min_load {
            min_load = l;
            idlest = cpu;
        }
    }

    if max_load.saturating_sub(min_load) > LOAD_THRESHOLD {
        migrate_one_task(busiest, idlest)
    } else {
        true
    }
}

