impl SigSet {
    /// Add a signal number to set.
    pub(crate) fn add_sig(&mut self, signo: usize) {
        if (1..=SIGRTMAX).contains(&signo) {
            self.bits |= 1u64 << (signo - 1);
        }
    }

    /// Remove a signal number from set.
    pub(crate) fn remove_sig(&mut self, signo: usize) {
        if (1..=SIGRTMAX).contains(&signo) {
            self.bits &= !(1u64 << (signo - 1));
        }
    }

    /// Check whether set contains signal.
    pub(crate) fn contain_sig(&self, signo: usize) -> bool {
        (1..=SIGRTMAX).contains(&signo) && (self.bits & (1u64 << (signo - 1))) != 0
    }
}

/// Whether the default disposition of a signal is to ignore it.
pub(crate) fn default_signal_is_ignore(signo: usize) -> bool {
    matches!(signo, SIGCHLD | SIGURG | SIGWINCH)
}

pub(crate) fn enqueue_current_itimer_real_signal_if_needed() {
    let Some(task) = current_task() else {
        return;
    };
    let clockid = {
        let inner = task.inner_exclusive_access();
        inner.itimer_real_clockid
    };
    let Ok(now) = clock_gettime_us(clockid) else {
        return;
    };
    let mut inner = task.inner_exclusive_access();
    if let Some(signo) = inner.queue_itimer_real_signal(now) {
        inner.sig_manager.enqueue_info(SigInfo::from_kernel(signo));
    }
}

/// Check whether the current task has any deliverable pending signal.
pub(crate) fn current_task_has_deliverable_signal() -> bool {
    enqueue_current_itimer_real_signal_if_needed();
    let Some(task) = crate::mission::current_task() else {
        return false;
    };
    let ret = task.inner_exclusive_access().sig_manager.has_deliverable();
    ret
}

/// Check whether the current task has a signal that should interrupt a syscall.
pub(crate) fn current_task_has_interrupting_signal(restartable_syscall: bool) -> bool {
    enqueue_current_itimer_real_signal_if_needed();
    let Some(task) = crate::mission::current_task() else {
        return false;
    };
    let ret = task
        .inner_exclusive_access()
        .sig_manager
        .has_interrupting_signal(restartable_syscall);
    ret
}

