fn default_dumps_core(signo: usize) -> bool {
    matches!(
        signo,
        SIGQUIT
            | SIGILL
            | SIGTRAP
            | SIGABRT
            | SIGBUS
            | SIGFPE
            | SIGSEGV
            | SIGXCPU
            | SIGXFSZ
            | SIGSYS
    )
}

const USER_SIGNAL_MIN_PC: usize = 0x1000;

fn terminate_current_with_default_action(
    task: Arc<crate::mission::TaskControlBlock>,
    signo: usize,
) {
    let dump_core = default_dumps_core(signo);
    if dump_core {
        write_minimal_core_dump(&task);
    }
    drop(task);
    exit_current_and_run_next(wait_status_signaled(signo, dump_core));
}

fn write_minimal_core_dump(task: &Arc<crate::mission::TaskControlBlock>) {
    let (path, dumpable, ranges, token) = {
        let inner = task.inner_exclusive_access();
        let cwd = inner.cwd.clone();
        let pid = task.pid.0;
        let dumpable = inner.dumpable;
        let mm = inner.mm.clone();
        drop(inner);
        let mm = mm.exclusive_access();
        (
            core_dump_path_for_cwd(pid, cwd.as_str()),
            dumpable,
            mm.dumpable_private_anon_ranges(),
            mm.activation().user_token(),
        )
    };
    if !dumpable {
        return;
    }
    if !tmp_ram_file_exists(path.as_str()) {
        let _ = open_file(path.as_str(), OpenFlags::CREATE | OpenFlags::WRONLY);
    }
    let mut file_off = 0usize;
    for (start, len) in ranges {
        let mut remaining = len;
        let mut addr = start;
        while remaining != 0 {
            let chunk = core::cmp::min(remaining, 4096);
            let bufs = crate::mm::translated_byte_buffer(token, addr as *const u8, chunk);
            if bufs.is_empty() {
                break;
            }
            for slice in bufs {
                let written = tmp_ram_write_at(path.as_str(), file_off, slice);
                file_off = file_off.saturating_add(written);
            }
            addr = addr.saturating_add(chunk);
            remaining = remaining.saturating_sub(chunk);
        }
    }
}

fn copy_to_user_bytes(token: usize, dst: usize, src: &[u8]) -> bool {
    if src.is_empty() {
        return true;
    }
    let mut copied = 0usize;
    for chunk in translated_byte_buffer(token, dst as *const u8, src.len()) {
        let len = chunk.len().min(src.len() - copied);
        chunk[..len].copy_from_slice(&src[copied..copied + len]);
        copied += len;
        if copied == src.len() {
            return true;
        }
    }
    false
}

/// Deliver at most one signal for current task before returning to user mode.
pub(crate) fn check_and_handle_current() {
    let task = match current_task() {
        Some(t) => t,
        None => return,
    };
    enqueue_current_itimer_real_signal_if_needed();
    let mut inner = task.inner_exclusive_access();
    if inner.in_signal_handler {
        return;
    }

    let Some(siginfo) = inner.sig_manager.dequeue_one_info() else {
        return;
    };
    let signo = siginfo.si_signo;
    if inner.itimer_real_signal_pending {
        inner.ack_itimer_real_signal(signo);
    }
    let action = match inner.sig_manager.get_action(signo) {
        Some(a) => a,
        None => SigAction::default(),
    };

    if action.sa_handler == SIG_IGN
        || (action.sa_handler == SIG_DFL && default_signal_is_ignore(signo))
    {
        return;
    }

    // Default terminate action.
    if action.sa_handler == SIG_DFL {
        drop(inner);
        terminate_current_with_default_action(task, signo);
        return;
    }

    if action.sa_handler < USER_SIGNAL_MIN_PC {
        log::warn!(
            "[signal] unsupported handler signo={} handler={:#x} restorer={:#x}, fallback to default action",
            signo,
            action.sa_handler,
            action.sa_restorer
        );
        drop(inner);
        terminate_current_with_default_action(task, signo);
        return;
    }
    // Our signal-return path restores context from kernel-saved state instead
    // of a Linux-style rt_sigframe on the user stack, so routing every handler
    // through the in-kernel trampoline keeps musl/glibc restorer differences
    // from leaking into user-visible behavior.
    let restorer = USER_SIGNAL_TRAMPOLINE;

    let old_cx = inner.get_trap_cx().clone();
    inner.saved_signal_trap_cx = Some(old_cx);
    inner.saved_signal_mask = inner.sig_manager.blocked().bits();
    inner.in_signal_handler = true;

    let mut blocked = inner.sig_manager.blocked();
    if (action.sa_flags & SigActionFlags::SA_NODEFER.bits()) == 0 {
        blocked.add_sig(signo);
    }
    blocked |= SigSet::from_bits_truncate(action.sa_mask);
    inner.sig_manager.set_blocked(blocked);

    let mut siginfo_ptr = 0usize;
    let mut handler_sp = inner.get_trap_cx().user_sp();
    if (action.sa_flags & SigActionFlags::SA_SIGINFO.bits()) != 0 {
        let token = inner.mm.exclusive_access().activation().user_token();
        let siginfo_frame = siginfo.to_user();
        let frame_size = core::mem::size_of::<UserSigInfo>();
        let Some(frame_base) = handler_sp.checked_sub(frame_size) else {
            drop(inner);
            terminate_current_with_default_action(task, SIGSEGV);
            return;
        };
        handler_sp = frame_base & !0xfusize;
        let raw = unsafe {
            core::slice::from_raw_parts(
                (&siginfo_frame as *const UserSigInfo) as *const u8,
                core::mem::size_of::<UserSigInfo>(),
            )
        };
        if !copy_to_user_bytes(token, handler_sp, raw) {
            drop(inner);
            terminate_current_with_default_action(task, SIGSEGV);
            return;
        }
        siginfo_ptr = handler_sp;
    }

    let cx = inner.get_trap_cx();
    cx.set_sp(handler_sp);
    cx.set_args3(signo, siginfo_ptr, 0);
    cx.set_user_ra(restorer);
    cx.set_user_pc(action.sa_handler);

    if (action.sa_flags & SigActionFlags::SA_RESETHAND.bits()) != 0 {
        let _ = inner.sig_manager.set_action(
            signo,
            SigAction {
                sa_handler: SIG_DFL,
                sa_flags: 0,
                sa_restorer: 0,
                sa_mask: 0,
            },
        );
    }
}

/// Restore context for `rt_sigreturn`.
pub(crate) fn sigreturn_current() -> isize {
    let task = match current_task() {
        Some(t) => t,
        None => return -1,
    };
    let mut inner = task.inner_exclusive_access();
    let Some(saved) = inner.saved_signal_trap_cx.take() else {
        return -1;
    };
    let old_mask = inner.saved_signal_mask;
    inner.in_signal_handler = false;
    inner
        .sig_manager
        .set_blocked(SigSet::from_bits_truncate(old_mask));
    *inner.get_trap_cx() = saved;
    inner.get_trap_cx().arg0() as isize
}

