#[cfg(feature = "syscall_profile")]
fn prof_delta(start: usize) -> usize {
    get_time().saturating_sub(start)
}

#[cfg(feature = "syscall_profile")]
fn prof_add(counter: &AtomicUsize, value: usize) {
    counter.fetch_add(value, Ordering::Relaxed);
}

/// Dump syscall/trap profile counters when enabled.
#[cfg(feature = "syscall_profile")]
pub(crate) fn dump_syscall_profile_stats() {
    let count = SYSCALL_PROF_COUNT.load(Ordering::Relaxed);
    if count == 0 {
        return;
    }
    println!(
        "[syscall-profile] count={} ticks total={} entry_sync={} classify={} get_cx={} dispatch={} account={} ret_cx={} check={}",
        count,
        SYSCALL_PROF_TOTAL_TICKS.load(Ordering::Relaxed),
        SYSCALL_PROF_ENTRY_SYNC_TICKS.load(Ordering::Relaxed),
        SYSCALL_PROF_CLASSIFY_TICKS.load(Ordering::Relaxed),
        SYSCALL_PROF_GET_CX_TICKS.load(Ordering::Relaxed),
        SYSCALL_PROF_DISPATCH_TICKS.load(Ordering::Relaxed),
        SYSCALL_PROF_ACCOUNT_TICKS.load(Ordering::Relaxed),
        SYSCALL_PROF_RET_CX_TICKS.load(Ordering::Relaxed),
        SYSCALL_PROF_CHECK_TICKS.load(Ordering::Relaxed)
    );
}

