struct Disk {
    block_id: usize,
    offset: usize,
    dev: Arc<dyn BlockDevice>,
}

impl Disk {
    fn new(dev: Arc<dyn BlockDevice>) -> Self {
        Self {
            block_id: 0,
            offset: 0,
            dev,
        }
    }

    fn set_position(&mut self, pos: u64) {
        self.block_id = pos as usize / BLOCK_SIZE;
        self.offset = pos as usize % BLOCK_SIZE;
    }

    fn position(&self) -> u64 {
        (self.block_id * BLOCK_SIZE + self.offset) as u64
    }

    fn read_one(&mut self, buf: &mut [u8]) -> Result<usize, i32> {
        let base_lba = EXT4_BASE_LBA.load(Ordering::Relaxed);
        let read_size = if self.offset == 0 && buf.len() >= BLOCK_SIZE {
            self.dev
                .read_block(base_lba + self.block_id, &mut buf[..BLOCK_SIZE]);
            self.block_id += 1;
            BLOCK_SIZE
        } else {
            let mut data = [0u8; BLOCK_SIZE];
            let start = self.offset;
            let count = buf.len().min(BLOCK_SIZE - self.offset);
            self.dev.read_block(base_lba + self.block_id, &mut data);
            buf[..count].copy_from_slice(&data[start..start + count]);
            self.offset += count;
            if self.offset >= BLOCK_SIZE {
                self.block_id += 1;
                self.offset -= BLOCK_SIZE;
            }
            count
        };
        Ok(read_size)
    }

    fn write_one(&mut self, buf: &[u8]) -> Result<usize, i32> {
        let base_lba = EXT4_BASE_LBA.load(Ordering::Relaxed);
        let write_size = if self.offset == 0 && buf.len() >= BLOCK_SIZE {
            self.dev
                .write_block(base_lba + self.block_id, &buf[..BLOCK_SIZE]);
            self.block_id += 1;
            BLOCK_SIZE
        } else {
            let mut data = [0u8; BLOCK_SIZE];
            let start = self.offset;
            let count = buf.len().min(BLOCK_SIZE - self.offset);
            self.dev.read_block(base_lba + self.block_id, &mut data);
            data[start..start + count].copy_from_slice(&buf[..count]);
            self.dev.write_block(base_lba + self.block_id, &data);
            self.offset += count;
            if self.offset >= BLOCK_SIZE {
                self.block_id += 1;
                self.offset -= BLOCK_SIZE;
            }
            count
        };
        Ok(write_size)
    }
}

