fn register_task(task: &Arc<TaskControlBlock>) {
    {
        let mut reg = TASK_LEAK_REGISTRY.exclusive_access();
        reg.retain(|w| w.strong_count() > 0);
        reg.push(Arc::downgrade(task));
    }

    let mut reg = TASK_REGISTRY.exclusive_access();
    reg.retain(|_, w| w.upgrade().is_some());
    let pid = task.pid.0;
    reg.insert(pid, Arc::downgrade(task));
}

fn lookup_registered_task(pid: usize) -> Option<Arc<TaskControlBlock>> {
    let mut reg = TASK_REGISTRY.exclusive_access();
    if let Some(task) = reg.get(&pid).and_then(|w| w.upgrade()) {
        return Some(task);
    }
    reg.remove(&pid);
    None
}

