fn write_user_u32_best_effort(token: usize, addr: usize, val: u32) -> bool {
    let raw = val.to_ne_bytes();
    let mut off = 0usize;
    for b in translated_byte_buffer(token, addr as *const u8, raw.len()) {
        let n = core::cmp::min(b.len(), raw.len() - off);
        b[..n].copy_from_slice(&raw[off..off + n]);
        off += n;
        if off >= raw.len() {
            return true;
        }
    }
    false
}

