        PIPE_READ_BYTES_TOTAL.load(Ordering::Relaxed),
        PIPE_WRITE_BYTES_TOTAL.load(Ordering::Relaxed),
        PIPE_READ_WAIT.load(Ordering::Relaxed),
        PIPE_WRITE_WAIT.load(Ordering::Relaxed),
        PIPE_READ_LOCK_LOOPS.load(Ordering::Relaxed),
        PIPE_WRITE_LOCK_LOOPS.load(Ordering::Relaxed)
    );
}

