impl TrapHal for Trap {
    fn init() {}

    fn set_kernel_trap_entry(entry: usize, _kernel_token: usize) {
        unsafe {
            stvec::write(entry, TrapMode::Direct);
        }
    }

    fn set_user_trap_entry(entry: usize) {
        unsafe {
            stvec::write(entry, TrapMode::Direct);
        }
    }

    fn ack_timer_interrupt() {}

    fn user_status_init_bits() -> usize {
        const SSTATUS_SPIE_BIT: usize = 1 << 5;
        unsafe {
            sstatus::set_fs(FS::Clean);
        }
        let mut status = sstatus::read();
        status.set_spp(SPP::User);
        status.bits() | SSTATUS_SPIE_BIT
    }

    fn is_user_mode(status_bits: usize) -> bool {
        const SSTATUS_SPP_BIT: usize = 1 << 8;
        (status_bits & SSTATUS_SPP_BIT) == 0
    }

    fn classify() -> TrapType {
        match scause::read().cause() {
            ScauseTrap::Exception(Exception::UserEnvCall) => TrapType::Syscall,
            ScauseTrap::Interrupt(Interrupt::SupervisorTimer) => TrapType::Timer,
            ScauseTrap::Exception(Exception::StoreFault)
            | ScauseTrap::Exception(Exception::StorePageFault) => TrapType::StorePageFault,
            ScauseTrap::Exception(Exception::LoadFault)
            | ScauseTrap::Exception(Exception::LoadPageFault) => TrapType::LoadPageFault,
            ScauseTrap::Exception(Exception::InstructionFault)
            | ScauseTrap::Exception(Exception::InstructionPageFault) => {
                TrapType::InstructionPageFault
            }
            ScauseTrap::Exception(Exception::IllegalInstruction) => TrapType::IllegalInstruction,
            _ => TrapType::Other,
        }
    }

    fn bad_addr() -> usize {
        stval::read()
    }

    fn exception_pc() -> usize {
        sepc::read()
    }

    fn user_sp_reg() -> usize {
        2
    }

    fn user_tp_reg() -> usize {
        4
    }

    fn arg0_reg() -> usize {
        10
    }

    fn syscall_id_reg() -> usize {
        17
    }

    fn trace_trap_state(context: &str, trap_type: TrapType, bad_addr: usize) {
        log::trace!(
            "[hal][rv][trap][{}] type={:?} sepc={:#x} bad={:#x}",
            context,
            trap_type,
            sepc::read(),
            bad_addr
        );
    }

    fn trap_runtime_uses_user_context() -> bool {
        true
    }

    fn trap_runtime_context_ptr() -> usize {
        extern "C" {
            fn __trap_restore_scratch();
        }
        __trap_restore_scratch as usize
    }

    fn trap_return_context_ptr(kernel_trap_cx_ptr: usize) -> usize {
        kernel_trap_cx_ptr
    }

    fn trap_return(trap_cx_ptr: usize, user_token: usize, _kernel_token: usize) -> ! {
        extern "C" {
            fn __alltraps();
            fn __restore();
        }
        let trampoline = Signal::trampoline_addr();
        let restore_va = __restore as usize - __alltraps as usize + trampoline;
        Self::set_user_trap_entry(trampoline);
        unsafe {
            asm!(
                "fence.i",
                "jr {restore_va}",
                restore_va = in(reg) restore_va,
                in("a0") trap_cx_ptr,
                in("a1") user_token,
                options(noreturn)
            );
        }
    }
}

