        sbi_call_ex(SBI_EXT_TIME, SBI_FID_SET_TIMER, timer, 0, 0);
    }

    fn console_putchar(c: usize) {
        sbi_call(SBI_CONSOLE_PUTCHAR, c, 0, 0);
    }

    fn console_getchar() -> usize {
        sbi_call(SBI_CONSOLE_GETCHAR, 0, 0, 0)
    }

    fn shutdown() -> ! {
        sbi_call_ex(SBI_EXT_SYSTEM_RESET, SBI_FID_SYSTEM_RESET, 0, 0, 0);
        sbi_call(SBI_SHUTDOWN, 0, 0, 0);
        loop {
            unsafe {
                core::arch::asm!("wfi");
            }
        }
    }

    fn terminate() -> ! {
        Self::shutdown()
    }
}

use super::{Firmware, FirmwareHal};
use crate::irq::Irq;

const DMW_BASE: usize = 0x9000_0000_0000_0000;
const UART0_BASE: usize = DMW_BASE | 0x1fe0_01e0;
const UART_RBR: usize = 0;
const UART_THR: usize = 0;
const UART_LSR: usize = 5;
const UART_LSR_DATA_READY: u8 = 1 << 0;
const UART_LSR_THR_EMPTY: u8 = 1 << 5;
const TCFG_EN: usize = 1;
const TCFG_INITVAL_SHIFT: usize = 2;
const TICLR_CLR: usize = 1;
const MIN_TIMER_INTERVAL: usize = 4;
const POWEROFF_REG_MMIO: usize = 0x8000_0000_100e_001c;
const POWEROFF_VALUE: u8 = 0x34;

#[inline]
fn read_time() -> usize {
    let mut counter: usize;
    unsafe {
        core::arch::asm!("rdtime.d {},{}", out(reg) counter, out(reg) _);
    }
    counter
}

#[inline]
fn clear_timer_interrupt() {
    unsafe {
        core::arch::asm!("csrwr {val}, 0x44", val = in(reg) TICLR_CLR);
    }
}

#[inline]
fn write_tcfg(value: usize) {
    unsafe {
        core::arch::asm!("csrwr {val}, 0x41", val = in(reg) value);
    }
}

#[inline]
fn normalize_timer_delta(delta: usize) -> usize {
    let base = delta.max(MIN_TIMER_INTERVAL);
    let aligned = base & !0x3;
    if aligned == 0 {
        MIN_TIMER_INTERVAL
    } else {
        aligned
    }
}

#[inline]
fn uart_read(offset: usize) -> u8 {
    unsafe { ((UART0_BASE + offset) as *const u8).read_volatile() }
}

#[inline]
fn uart_write(offset: usize, value: u8) {
    unsafe { ((UART0_BASE + offset) as *mut u8).write_volatile(value) }
}

fn poweroff() -> ! {
    Irq::disable_timer_interrupt();
    log::info!(
        "[hal][la][firmware] shutdown: write {:#x} to {:#x}",
        POWEROFF_VALUE,
        POWEROFF_REG_MMIO
    );
    unsafe {
        (POWEROFF_REG_MMIO as *mut u8).write_volatile(POWEROFF_VALUE);
        core::arch::asm!("dbar 0");
    }
    loop {
        unsafe {
            core::arch::asm!("idle 0");
        }
    }
}

impl FirmwareHal for Firmware {
    fn set_timer(timer: usize) {
        let now = read_time();
        let delta = normalize_timer_delta(timer.saturating_sub(now));
        clear_timer_interrupt();
        write_tcfg((delta << TCFG_INITVAL_SHIFT) | TCFG_EN);
        log::trace!(
            "[hal][la][firmware] set_timer now={:#x} target={:#x} delta={:#x}",
            now,
            timer,
            delta
        );
    }

    fn console_putchar(c: usize) {
        while (uart_read(UART_LSR) & UART_LSR_THR_EMPTY) == 0 {}
        uart_write(UART_THR, c as u8);
    }

    fn console_getchar() -> usize {
        if (uart_read(UART_LSR) & UART_LSR_DATA_READY) == 0 {
            0
        } else {
            uart_read(UART_RBR) as usize
        }
    }

    fn shutdown() -> ! {
        poweroff()
    }

    fn terminate() -> ! {
        poweroff()
    }
}

