fn current_memlock_limit() -> Option<usize> {
    let task = current_task()?;
    let inner = task.inner_exclusive_access();
    if inner.euid == 0 {
        None
    } else {
        Some(inner.rlimits[RLIMIT_MEMLOCK].cur)
    }
}

