}

pub fn sys_mlock(start: usize, len: usize) -> isize {
    let _vm_sync = VM_LAYOUT_SYNC.exclusive_access();
    let task = current_task().unwrap();
    task.lock_memory(start, len, true, false, current_memlock_limit())
        .map(|_| 0)
        .unwrap_or_else(|err| err)
}

pub fn sys_munlock(start: usize, len: usize) -> isize {
    let _vm_sync = VM_LAYOUT_SYNC.exclusive_access();
    let task = current_task().unwrap();
    task.lock_memory(start, len, false, false, None)
        .map(|_| 0)
        .unwrap_or_else(|err| err)
}

pub fn sys_mlock2(start: usize, len: usize, flags: usize) -> isize {
    if flags & !MLOCK_ONFAULT != 0 {
        return EINVAL;
    }
    let _vm_sync = VM_LAYOUT_SYNC.exclusive_access();
    let task = current_task().unwrap();
    task.lock_memory(
        start,
        len,
        true,
        (flags & MLOCK_ONFAULT) != 0,
        current_memlock_limit(),
    )
    .map(|_| 0)
    .unwrap_or_else(|err| err)
}

pub fn sys_msync(start: usize, len: usize, flags: usize) -> isize {
    let known_flags = MS_ASYNC | MS_INVALIDATE | MS_SYNC;
    if (flags & !known_flags) != 0 || (flags & MS_ASYNC != 0 && flags & MS_SYNC != 0) {
        return EINVAL;
    }
    if len == 0 {
        return if (start & (PAGE_SIZE - 1)) == 0 {
            0
        } else {
            EINVAL
        };
    }
    if (start & (PAGE_SIZE - 1)) != 0 {
        return EINVAL;
    }
    let aligned = match len.checked_add(PAGE_SIZE - 1).map(|v| v & !(PAGE_SIZE - 1)) {
        Some(v) if v != 0 => v,
        _ => return EINVAL,
    };
    let end = match start.checked_add(aligned) {
        Some(v) => v,
        None => return EINVAL,
    };
    if start >= TRAMPOLINE || end > TRAMPOLINE {
        return EINVAL;
    }

    let _vm_sync = VM_LAYOUT_SYNC.exclusive_access();
    let task = current_task().unwrap();
    task.msync(start, aligned, (flags & MS_INVALIDATE) != 0)
        .map(|_| 0)
        .unwrap_or_else(|err| err)
}

pub fn sys_mlockall(flags: usize) -> isize {
    if flags == 0 || (flags & !(MCL_CURRENT | MCL_FUTURE | MCL_ONFAULT)) != 0 {
        return EINVAL;
    }
    if (flags & MCL_ONFAULT) != 0 && (flags & (MCL_CURRENT | MCL_FUTURE)) == 0 {
        return EINVAL;
    }

    let _vm_sync = VM_LAYOUT_SYNC.exclusive_access();
    if (flags & MCL_CURRENT) == 0 {
        return 0;
    }
    let task = current_task().unwrap();
    task.mlock_all_current((flags & MCL_ONFAULT) != 0, current_memlock_limit())
        .map(|_| 0)
        .unwrap_or_else(|err| err)
}

pub fn sys_munlockall() -> isize {
    let _vm_sync = VM_LAYOUT_SYNC.exclusive_access();
    let task = current_task().unwrap();
    task.munlock_all();
    0
}

fn copy_to_user_retry(dst: *mut u8, src: &[u8]) -> Result<(), isize> {
    if src.is_empty() {
        return Ok(());
    }
    if dst.is_null() {
        return Err(EFAULT);
    }
    let token = current_mm_activation().user_token();
    let mut copied = 0usize;
    for buf in translated_byte_buffer(token, dst as *const u8, src.len()) {
        let n = core::cmp::min(buf.len(), src.len().saturating_sub(copied));
        buf[..n].copy_from_slice(&src[copied..copied + n]);
        copied += n;
        if copied >= src.len() {
            return Ok(());
        }
    }
    Err(EFAULT)
}

