//! Generic virtual mapping materialization helpers.

use super::page_table::{PageSizeKind, PageTable};
use super::PTEFlags;
use super::VPNRange;
use super::{
    frame_alloc, frame_dealloc, huge_1g_alloc, huge_1g_dealloc, huge_2m_alloc, huge_2m_dealloc,
    FrameTracker, PhysPageNum, VirtAddr, VirtPageNum, HUGE_1G_PAGES, HUGE_2M_PAGES,
};
use alloc::collections::BTreeMap;
use bitflags::*;

/// Minimum length, in pages, before a 2MiB huge page is considered.
const HUGE_2M_MIN_PAGES: usize = HUGE_2M_PAGES * 2;
/// Minimum length, in pages, before a 1GiB huge page is considered.
const HUGE_1G_MIN_PAGES: usize = HUGE_1G_PAGES * 2;

/// A generic contiguous virtual mapping materialized into a page table.
pub(super) struct MapArea {
    /// Covered virtual page range.
    pub(super) vpn_range: VPNRange,
    /// Owned 4KiB data frames for framed mappings.
    pub(super) data_frames: BTreeMap<VirtPageNum, FrameTracker>,
    /// Owned huge-page leaves keyed by start VPN.
    pub(super) huge_pages: BTreeMap<VirtPageNum, (PhysPageNum, PageSizeKind)>,
    /// Whether user mappings in this area may use huge-page leaves.
    pub(super) user_huge_allowed: bool,
    /// Physical backing policy.
    pub(super) map_type: MapType,
    /// PTE permission bits for this mapping.
    pub(super) map_perm: MapPermission,
}

impl MapArea {
    /// Create a new generic mapping area.
    pub(super) fn new(
        start_va: VirtAddr,
        end_va: VirtAddr,
        map_type: MapType,
        map_perm: MapPermission,
    ) -> Self {
        let start_vpn: VirtPageNum = start_va.floor();
        let end_vpn: VirtPageNum = end_va.ceil();
        Self {
            vpn_range: VPNRange::new(start_vpn, end_vpn),
            data_frames: BTreeMap::new(),
            huge_pages: BTreeMap::new(),
            user_huge_allowed: false,
            map_type,
            map_perm,
        }
    }

    /// Return the first VPN covered by this area.
    pub(super) fn start_vpn(&self) -> VirtPageNum {
        self.vpn_range.get_start()
    }

    /// Return the exclusive end VPN covered by this area.
    pub(super) fn end_vpn(&self) -> VirtPageNum {
        self.vpn_range.get_end()
    }

    /// Clone this area without carrying mapped frame ownership.
    pub(super) fn clone_empty(&self) -> Self {
        Self {
            vpn_range: VPNRange::new(self.start_vpn(), self.end_vpn()),
            data_frames: BTreeMap::new(),
            huge_pages: BTreeMap::new(),
            user_huge_allowed: self.user_huge_allowed,
            map_type: self.map_type,
            map_perm: self.map_perm,
        }
    }

    fn advance_vpn(vpn: VirtPageNum, size: PageSizeKind) -> VirtPageNum {
        VirtPageNum(
            vpn.0
                + match size {
                    PageSizeKind::Size1G => HUGE_1G_PAGES,
                    PageSizeKind::Size2M => HUGE_2M_PAGES,
                    PageSizeKind::Size4K => 1,
                },
        )
    }

    fn translated_valid_ppn(page_table: &PageTable, vpn: VirtPageNum) -> Option<PhysPageNum> {
        page_table
            .translate(vpn)
            .filter(|pte| pte.is_valid())
            .map(|pte| pte.ppn())
    }

    fn try_map_best_fit(
        &mut self,
        page_table: &mut PageTable,
        vpn: VirtPageNum,
        remain_pages: usize,
    ) -> Option<PageSizeKind> {
        if self.can_use_huge(vpn, remain_pages, HUGE_1G_MIN_PAGES, HUGE_1G_PAGES)
            && self.map_huge(page_table, vpn, PageSizeKind::Size1G)
        {
            return Some(PageSizeKind::Size1G);
        }
        if self.can_use_huge(vpn, remain_pages, HUGE_2M_MIN_PAGES, HUGE_2M_PAGES)
            && self.map_huge(page_table, vpn, PageSizeKind::Size2M)
        {
            return Some(PageSizeKind::Size2M);
        }
        if self.map_4k(page_table, vpn) {
            return Some(PageSizeKind::Size4K);
        }
        None
    }

    fn unmap_range_impl(
        &mut self,
        page_table: &mut PageTable,
        mut vpn: VirtPageNum,
        end: VirtPageNum,
    ) {
        while vpn < end {
            if let Some((_, size)) = self.huge_pages.get(&vpn).copied() {
                self.unmap_one(page_table, vpn);
                vpn = Self::advance_vpn(vpn, size);
                continue;
            }
            self.unmap_one(page_table, vpn);
            vpn = Self::advance_vpn(vpn, PageSizeKind::Size4K);
        }
    }

    fn can_use_huge(
        &self,
        vpn: VirtPageNum,
        remain_pages: usize,
        min_pages: usize,
        align_pages: usize,
    ) -> bool {
        if remain_pages < min_pages {
            return false;
        }
        if self.map_type != MapType::Identical && self.map_type != MapType::Framed {
            return false;
        }
        if self.map_perm.contains(MapPermission::U) && !self.user_huge_allowed {
            return false;
        }
        vpn.0 % align_pages == 0
    }

    fn alloc_4k_ppn(&mut self, vpn: VirtPageNum) -> Option<PhysPageNum> {
        match self.map_type {
            MapType::Identical => Some(PhysPageNum(vpn.0)),
            MapType::Framed => {
                let frame = frame_alloc()?;
                let ppn = frame.ppn;
                self.data_frames.insert(vpn, frame);
                Some(ppn)
            }
        }
    }

    fn dealloc_unowned_4k_ppn(&self, ppn: PhysPageNum, owned: bool) {
        if self.map_type == MapType::Framed && !owned {
            frame_dealloc(ppn);
        }
    }

    fn map_4k(&mut self, page_table: &mut PageTable, vpn: VirtPageNum) -> bool {
        let Some(ppn) = self.alloc_4k_ppn(vpn) else {
            return false;
        };
        let pte_flags = PTEFlags::from_bits_truncate(self.map_perm.bits);
        page_table.map(vpn, ppn, pte_flags);
        true
    }

