        unsafe {
            core::arch::asm!("sfence.vma {addr}, x0", addr = in(reg) vaddr);
        }
    }

    fn phys_to_virt_kernel(paddr: usize) -> usize {
        paddr
    }

    fn virt_to_phys_kernel(vaddr: usize) -> usize {
        let satp = riscv::register::satp::read().bits();
        let mut ppn = token_ppn(satp);
        let idxs = vpn_indexes(vaddr);
        for (level, idx) in idxs.iter().enumerate() {
            let table_pa = ppn << PAGE_SIZE_BITS;
            let pte_ptr = (table_pa + idx * size_of::<RvPte>()) as *const RvPte;
            let pte = unsafe { core::ptr::read_volatile(pte_ptr) };
            let bits = pte.bits;
            if !pte_valid(bits) {
                return 0;
            }
            if pte_is_leaf(bits) {
                let base_ppn = pte_ppn(bits);
                let offset_mask = match level {
                    0 => (1usize << 30) - 1,
                    1 => (1usize << 21) - 1,
                    _ => (1usize << 12) - 1,
                };
                return (base_ppn << PAGE_SIZE_BITS) + (vaddr & offset_mask);
            }
            ppn = pte_ppn(bits);
        }
        0
    }

    fn addr_spec() -> AddrSpec {
        AddrSpec {
            pa_width: 56,
            va_width: 39,
            pt_levels: 3,
            pt_index_bits: 9,
        }
    }

    fn token_mode_bits() -> usize {
        8usize << 60
    }

    fn pte_ppn(bits: usize) -> usize {
        (bits >> PTE_PPN_SHIFT) & ((1usize << token_ppn_width()) - 1)
    }

    fn pte_flags(bits: usize) -> usize {
        bits & ((1usize << PTE_FLAG_BITS) - 1)
    }

    fn pte_sw_cow_bit() -> usize {
        PTE_SW_COW_BIT
    }

    fn make_pte_bits(ppn: usize, flags: usize, sw_bits: usize) -> usize {
        let ppn_bits = (ppn & ((1usize << token_ppn_width()) - 1)) << PTE_PPN_SHIFT;
        ppn_bits | (flags & ((1usize << PTE_FLAG_BITS) - 1)) | sw_bits
    }
}

