const EAGAIN: isize = -11;
const EINVAL: isize = -22;
const EVENTFD_COUNTER_MAX: u64 = u64::MAX - 1;

struct EventFdState {
    counter: u64,
    nonblock: bool,
}

pub(crate) struct EventFdFile {
    state: UPSafeCell<EventFdState>,
    semaphore: bool,
}

impl EventFdFile {
    pub(crate) fn new(initval: u32, semaphore: bool, nonblock: bool) -> Self {
        Self {
            state: unsafe {
                UPSafeCell::new(EventFdState {
                    counter: initval as u64,
                    nonblock,
                })
            },
            semaphore,
        }
    }

    pub(crate) fn is_nonblock(&self) -> bool {
        self.state.exclusive_access().nonblock
    }

    pub(crate) fn set_nonblock(&self, nonblock: bool) {
        self.state.exclusive_access().nonblock = nonblock;
    }

    pub(crate) fn poll_readable(&self) -> bool {
        self.state.exclusive_access().counter > 0
    }

    pub(crate) fn poll_writable(&self) -> bool {
        self.state.exclusive_access().counter < EVENTFD_COUNTER_MAX
    }

    pub(crate) fn read_u64(&self) -> Result<u64, isize> {
        loop {
            let mut state = self.state.exclusive_access();
            if state.counter > 0 {
                let ret = if self.semaphore {
                    state.counter -= 1;
                    1
                } else {
                    let current = state.counter;
                    state.counter = 0;
                    current
                };
                return Ok(ret);
            }
            if state.nonblock {
                return Err(EAGAIN);
            }
            drop(state);
            suspend_current_and_run_next();
        }
    }

    pub(crate) fn write_u64(&self, val: u64) -> Result<(), isize> {
        if val == u64::MAX {
            return Err(EINVAL);
        }
        loop {
            let mut state = self.state.exclusive_access();
            if val <= EVENTFD_COUNTER_MAX.saturating_sub(state.counter) {
                state.counter += val;
                return Ok(());
            }
            if state.nonblock {
                return Err(EAGAIN);
            }
            drop(state);
            suspend_current_and_run_next();
        }
    }
}

