use super::{note_block_batch, BlockDevice};
use crate::mm::{frame_alloc, frame_dealloc, FrameTracker, PhysAddr, PhysPageNum, StepByOne};
use crate::sync::SpinMutex;
use alloc::vec::Vec;
use core::ptr::NonNull;
use hal::pagetable::PageTable as ArchPageTable;
use hal::virtio::{Virtio as ArchVirtio, VirtioBlkTransport};
use lazy_static::*;
use virtio_drivers::device::blk::VirtIOBlk;
use virtio_drivers::{BufferDirection, Hal};

type VirtioBlkDriver = VirtIOBlk<VirtioHal, VirtioBlkTransport>;
const VIRTIO_SHARED_BUFFER_LIMIT: usize = 4096;

/// VirtIOBlock device driver strcuture for virtio_blk device
pub(crate) struct VirtIOBlock {
    inner: SpinMutex<VirtioBlkDriver>,
    capacity_blocks: usize,
}

lazy_static! {
    static ref QUEUE_FRAMES: SpinMutex<Vec<FrameTracker>> = SpinMutex::new(Vec::new());
    static ref SHARED_BUFFERS: SpinMutex<Vec<SharedBuffer>> = SpinMutex::new(Vec::new());
}

struct SharedBuffer {
    paddr: usize,
    len: usize,
    frame: FrameTracker,
}

impl BlockDevice for VirtIOBlock {
    fn read_block(&self, block_id: usize, buf: &mut [u8]) {
        self.inner
            .lock()
            .read_blocks(block_id, buf)
            .unwrap_or_else(|err| {
                panic!(
                    "Error when reading VirtIOBlk: block_id={} len={} total_blocks={} err={:?}",
                    block_id,
                    buf.len(),
                    self.capacity_blocks,
                    err
                )
            });
    }
    fn write_block(&self, block_id: usize, buf: &[u8]) {
        self.inner
            .lock()
            .write_blocks(block_id, buf)
            .unwrap_or_else(|err| {
                panic!(
                    "Error when writing VirtIOBlk: block_id={} len={} total_blocks={} err={:?}",
                    block_id,
                    buf.len(),
                    self.capacity_blocks,
                    err
                )
            });
    }
    fn read_blocks(&self, block_id: usize, buf: &mut [u8]) {
        note_block_batch(false, buf.len() / 512);
        assert!(
            buf.len() % 512 == 0,
            "VirtIOBlk batch read must be block-aligned: len={}",
            buf.len()
        );
        let mut driver = self.inner.lock();
        for (chunk_idx, chunk) in buf.chunks_mut(VIRTIO_SHARED_BUFFER_LIMIT).enumerate() {
            let chunk_block = block_id + chunk_idx * (VIRTIO_SHARED_BUFFER_LIMIT / 512);
            driver.read_blocks(chunk_block, chunk).unwrap_or_else(|err| {
                panic!(
                    "Error when reading VirtIOBlk batch chunk: block_id={} len={} total_blocks={} err={:?}",
                    chunk_block,
                    chunk.len(),
                    self.capacity_blocks,
                    err
                )
            });
        }
    }
    fn write_blocks(&self, block_id: usize, buf: &[u8]) {
        note_block_batch(true, buf.len() / 512);
        assert!(
            buf.len() % 512 == 0,
            "VirtIOBlk batch write must be block-aligned: len={}",
            buf.len()
        );
        let mut driver = self.inner.lock();
        for (chunk_idx, chunk) in buf.chunks(VIRTIO_SHARED_BUFFER_LIMIT).enumerate() {
            let chunk_block = block_id + chunk_idx * (VIRTIO_SHARED_BUFFER_LIMIT / 512);
            driver.write_blocks(chunk_block, chunk).unwrap_or_else(|err| {
                panic!(
                    "Error when writing VirtIOBlk batch chunk: block_id={} len={} total_blocks={} err={:?}",
                    chunk_block,
                    chunk.len(),
                    self.capacity_blocks,
                    err
                )
            });
        }
    }
    fn total_blocks(&self) -> usize {
        self.capacity_blocks
    }
}

impl VirtIOBlock {
    /// Create a new VirtIOBlock driver.
    pub(crate) fn new() -> Self {
        let driver = new_virtio_blk_driver();
        let capacity_blocks = driver.capacity() as usize;
        Self {
            inner: SpinMutex::new(driver),
            capacity_blocks,
        }
    }
}

fn new_virtio_blk_driver() -> VirtioBlkDriver {
    let transport = ArchVirtio::new_blk_transport::<VirtioHal>();
    VirtIOBlk::<VirtioHal, _>::new(transport).unwrap()
}

pub(crate) struct VirtioHal;

unsafe impl Hal for VirtioHal {
    fn dma_alloc(pages: usize, _direction: BufferDirection) -> (usize, NonNull<u8>) {
        let mut ppn_base = PhysPageNum(0);
        for i in 0..pages {
            let frame = frame_alloc().unwrap();
            if i == 0 {
                ppn_base = frame.ppn;
            }
            assert_eq!(frame.ppn.0, ppn_base.0 + i);
            QUEUE_FRAMES.lock().push(frame);
        }
        let pa: PhysAddr = ppn_base.into();
        let va = ArchPageTable::phys_to_virt_kernel(pa.0);
        (pa.0, NonNull::new(va as *mut u8).unwrap())
    }

    unsafe fn dma_dealloc(paddr: usize, _vaddr: NonNull<u8>, pages: usize) -> i32 {
        let pa = PhysAddr::from(paddr);
        let mut ppn_base: PhysPageNum = pa.into();
        for _ in 0..pages {
            frame_dealloc(ppn_base);
            ppn_base.step();
        }
        0
    }

    unsafe fn mmio_phys_to_virt(paddr: usize, _size: usize) -> NonNull<u8> {
        let vaddr = ArchPageTable::phys_to_virt_kernel(paddr);
        NonNull::new(vaddr as *mut u8).unwrap()
    }

    unsafe fn share(buffer: NonNull<[u8]>, _direction: BufferDirection) -> usize {
        let src = buffer.as_ref();
        assert!(
            src.len() <= VIRTIO_SHARED_BUFFER_LIMIT,
            "VirtIO shared buffer too large: len={}",
            src.len()
        );

        let frame = frame_alloc().expect("VirtIO shared buffer allocation failed");
        let paddr: PhysAddr = frame.ppn.into();
        let bounce = frame.ppn.get_bytes_array();
        if matches!(
            _direction,
            BufferDirection::DriverToDevice | BufferDirection::Both
        ) {
            bounce[..src.len()].copy_from_slice(src);
        }
        SHARED_BUFFERS.lock().push(SharedBuffer {
            paddr: paddr.0,
            len: src.len(),
            frame,
        });
        paddr.0
    }

    unsafe fn unshare(paddr: usize, mut buffer: NonNull<[u8]>, direction: BufferDirection) {
        let mut shared = SHARED_BUFFERS.lock();
        let index = shared
            .iter()
            .position(|entry| entry.paddr == paddr)
            .unwrap_or_else(|| panic!("VirtIO shared buffer not found: paddr={:#x}", paddr));
        let entry = shared.swap_remove(index);
        let dst = buffer.as_mut();
        assert_eq!(
            dst.len(),
            entry.len,
            "VirtIO shared buffer length changed: paddr={:#x} old_len={} new_len={}",
            paddr,
            entry.len,
            dst.len()
        );
        if matches!(
            direction,
            BufferDirection::DeviceToDriver | BufferDirection::Both
        ) {
            dst.copy_from_slice(&entry.frame.ppn.get_bytes_array()[..entry.len]);
        }
    }
}

use super::{
    action::{action_valid_signal, KSigAction, SigAction, SigActionFlags},
    default_signal_is_ignore,
    msg_queue::{SigInfo, SignalMsgQueue},
    SigSet, SIGKILL, SIGRTMAX, SIGSTOP, SIG_DFL, SIG_IGN,
};

/// Per-task signal state.
#[derive(Clone)]
pub(crate) struct SignalManager {
    queue: SignalMsgQueue,
    blocked: SigSet,
    actions: [KSigAction; SIGRTMAX + 1],
}

impl SignalManager {
    /// Create an empty signal manager.
    pub(crate) fn new() -> Self {
        Self {
            queue: SignalMsgQueue::new(),
            blocked: SigSet::empty(),
            actions: core::array::from_fn(KSigAction::default_for),
        }
    }

    /// Fork-copy semantics: handlers+mask inherited, pending cleared.
    pub(crate) fn from_fork(other: &Self) -> Self {
        Self {
            queue: SignalMsgQueue::new(),
            blocked: other.blocked,
            actions: other.actions,
        }
    }

    /// Reset on exec: keep blocked mask, reset user-installed handlers.
    pub(crate) fn reset_on_exec(&mut self) {
        for signo in 1..=SIGRTMAX {
            if self.actions[signo].is_user {
                self.actions[signo] = KSigAction::default_for(signo);
            }
        }
    }

    /// Enqueue one pending signal with full siginfo payload.
    pub(crate) fn enqueue_info(&mut self, info: SigInfo) {
        self.queue.push(info);
    }

    /// Current blocked mask.
    pub(crate) fn blocked(&self) -> SigSet {
        self.blocked
    }

    /// Replace blocked mask (`SIGKILL/SIGSTOP` are always unblocked).
    pub(crate) fn set_blocked(&mut self, mut set: SigSet) {
        set.remove_sig(SIGKILL);
        set.remove_sig(SIGSTOP);
        self.blocked = set;
    }

    /// Dequeue first deliverable signal (std first, then rt).
    pub(crate) fn dequeue_one_info(&mut self) -> Option<SigInfo> {
        self.queue.pop_deliverable(self.blocked, SIGKILL, SIGSTOP)
    }

    /// Dequeue first pending signal info that belongs to `set`.
    pub(crate) fn dequeue_matching_info(&mut self, set: SigSet) -> Option<SigInfo> {
        self.queue.pop_matching(set)
    }

    /// Dequeue first pending signal that belongs to `set`.
    pub(crate) fn dequeue_matching(&mut self, set: SigSet) -> Option<usize> {
        self.dequeue_matching_info(set).map(|si| si.si_signo)
    }

    /// Check whether there is at least one deliverable pending signal.
    pub(crate) fn has_deliverable(&self) -> bool {
        self.queue.has_deliverable(self.blocked, SIGKILL, SIGSTOP)
    }

    /// Check whether a blocking syscall should be interrupted now.
    ///
    /// This filters out signals that are currently ignored by action/mask and
    /// keeps `SA_RESTART` handlers from surfacing as user-visible `EINTR`.
    pub(crate) fn has_interrupting_signal(&self, restartable_syscall: bool) -> bool {
        for signo in 1..=SIGRTMAX {
            if signo != SIGKILL && signo != SIGSTOP && self.blocked.contain_sig(signo) {
                continue;
            }
            if !self.queue.has_pending(signo) {
                continue;
            }

            let action = self.actions[signo].action;
            if action.sa_handler == SIG_IGN
                || (action.sa_handler == SIG_DFL && default_signal_is_ignore(signo))
            {
                continue;
            }

            if restartable_syscall
                && action.sa_handler != SIG_DFL
                && (action.sa_flags & SigActionFlags::SA_RESTART.bits()) != 0
            {
                continue;
            }

            return true;
        }
        false
    }

    /// Return pending signals that are currently blocked from delivery.
    pub(crate) fn pending_blocked(&self) -> SigSet {
        self.queue.pending_mask() & self.blocked
    }

    /// Set one signal action.
    pub(crate) fn set_action(&mut self, signo: usize, action: SigAction) -> bool {
        if !action_valid_signal(signo) {
            return false;
        }
        let is_user = action.sa_handler != super::SIG_DFL && action.sa_handler != super::SIG_IGN;
        self.actions[signo] = KSigAction { action, is_user };
        true
    }

    /// Get one signal action in user ABI form.
    pub(crate) fn get_action(&self, signo: usize) -> Option<SigAction> {
        if !(1..=SIGRTMAX).contains(&signo) {
            return None;
        }
        Some(self.actions[signo].action)
    }
}

use super::{SIGKILL, SIGRTMAX, SIGSTOP};

/// Default action handler value.
pub(crate) const SIG_DFL: usize = 0;
/// Ignore action handler value.
pub(crate) const SIG_IGN: usize = 1;

/// Linux `sigaction` (rt variant) layout for rv64/la64.
#[repr(C)]
#[derive(Clone, Copy, Debug, Default)]
pub(crate) struct SigAction {
    /// Handler pointer (`SIG_DFL`/`SIG_IGN` or function address).
    pub sa_handler: usize,
    /// Flags (`SA_*`).
    pub sa_flags: usize,
    /// Restorer trampoline.
    pub sa_restorer: usize,
    /// Additional blocked mask during handler execution.
    pub sa_mask: u64,
}

bitflags! {
    /// `sa_flags` bits.
    pub(crate) struct SigActionFlags: usize {
        /// `SA_SIGINFO`
        const SA_SIGINFO = 0x0000_0004;
        /// `SA_RESTORER`
        const SA_RESTORER = 0x0400_0000;
        /// `SA_RESTART`
        const SA_RESTART = 0x1000_0000;
        /// `SA_NODEFER`
        const SA_NODEFER = 0x4000_0000;
        /// `SA_RESETHAND`
        const SA_RESETHAND = 0x8000_0000;
    }
}

#[derive(Clone, Copy)]
pub(crate) struct KSigAction {
    pub(crate) action: SigAction,
    pub(crate) is_user: bool,
}

impl KSigAction {
    pub(crate) fn default_for(_signo: usize) -> Self {
        Self {
            action: SigAction {
                sa_handler: SIG_DFL,
                sa_flags: 0,
                sa_restorer: 0,
                sa_mask: 0,
            },
            is_user: false,
        }
    }
}

pub(crate) fn action_valid_signal(signo: usize) -> bool {
    (1..=SIGRTMAX).contains(&signo) && signo != SIGKILL && signo != SIGSTOP
}

//! Small virtual passwd/group database used by libc account lookups.

use alloc::collections::BTreeMap;
use alloc::format;
use alloc::string::{String, ToString};
use alloc::vec::Vec;
use lazy_static::lazy_static;

use crate::sync::UPSafeCell;

const BASE_PASSWD: &str = "root:x:0:0:root:/root:/bin/sh\n\
bin:x:1:1:bin:/bin:/usr/sbin/nologin\n\
daemon:x:2:2:daemon:/usr/sbin:/usr/sbin/nologin\n\
nobody:x:65534:65534:nobody:/nonexistent:/usr/sbin/nologin\n";

const BASE_GROUP: &str = "root:x:0:\n\
bin:x:1:\n\
daemon:x:2:\n\
sys:x:3:\n\
users:x:100:\n\
nogroup:x:65534:\n";

struct UserDb {
    next_uid: u32,
    users: BTreeMap<String, u32>,
}

impl UserDb {
    fn new() -> Self {
        Self {
            next_uid: 1000,
            users: BTreeMap::new(),
        }
    }
}

lazy_static! {
    static ref USER_DB: UPSafeCell<UserDb> = unsafe { UPSafeCell::new(UserDb::new()) };
}

fn command_user_arg(args: &[String]) -> Option<&str> {
    args.iter()
        .skip(1)
        .rev()
        .find(|arg| !arg.starts_with('-'))
        .map(|arg| arg.as_str())
}

/// Apply a user-management command requested by LTP through busybox fallback.
pub(crate) fn apply_user_command(applet: &str, args: &[String]) -> bool {
    match applet {
        "useradd" | "adduser" => {
            if let Some(name) = command_user_arg(args) {
                let mut db = USER_DB.exclusive_access();
                if !db.users.contains_key(name) {
                    let uid = db.next_uid;
                    db.next_uid = db.next_uid.saturating_add(1);
                    db.users.insert(name.to_string(), uid);
                }
            }
            true
        }
        "userdel" | "deluser" => {
            if let Some(name) = command_user_arg(args) {
                USER_DB.exclusive_access().users.remove(name);
            }
            true
        }
        "groupdel" | "delgroup" => true,
        _ => false,
    }
}

/// Return virtual `/etc/passwd` contents including users added at runtime.
pub(crate) fn passwd_data() -> Vec<u8> {
    let db = USER_DB.exclusive_access();
    let mut out = BASE_PASSWD.to_string();
    for (name, uid) in db.users.iter() {
        out.push_str(
            format!(
                "{}:x:{}:{}:{}:/home/{}:/bin/sh\n",
                name, uid, uid, name, name
            )
            .as_str(),
        );
    }
    out.into_bytes()
}

/// Return virtual `/etc/group` contents including groups added at runtime.
pub(crate) fn group_data() -> Vec<u8> {
    let db = USER_DB.exclusive_access();
    let mut out = BASE_GROUP.to_string();
    for (name, uid) in db.users.iter() {
        out.push_str(format!("{}:x:{}:\n", name, uid).as_str());
    }
    out.into_bytes()
}

