static TCB_ALLOC_HIT: AtomicUsize = AtomicUsize::new(0);
static TCB_ALLOC_MISS: AtomicUsize = AtomicUsize::new(0);
static TCB_RECYCLE_HIT: AtomicUsize = AtomicUsize::new(0);
static TCB_RECYCLE_DROP: AtomicUsize = AtomicUsize::new(0);
static INODE_ALLOC_HIT: AtomicUsize = AtomicUsize::new(0);
static INODE_ALLOC_MISS: AtomicUsize = AtomicUsize::new(0);
static INODE_RECYCLE_HIT: AtomicUsize = AtomicUsize::new(0);
static INODE_RECYCLE_DROP: AtomicUsize = AtomicUsize::new(0);

#[repr(C)]
struct FreeNode {
    next: *mut FreeNode,
}

#[derive(Copy, Clone)]
struct SlabCache {
    size: usize,
    align: usize,
    limit: usize,
    len: usize,
    head: *mut FreeNode,
}

enum CacheKind {
    Tcb,
    Inode,
}

impl SlabCache {
    const fn new(size: usize, align: usize, limit: usize) -> Self {
        Self {
            size,
            align,
            limit,
            len: 0,
            head: null_mut(),
        }
    }

    fn matches(&self, layout: Layout) -> bool {
        layout.size() == self.size && layout.align() == self.align
    }

    unsafe fn pop(&mut self) -> *mut u8 {
        if self.head.is_null() {
            return null_mut();
        }
        let node = self.head;
        self.head = (*node).next;
        self.len -= 1;
        node as *mut u8
    }

    unsafe fn push(&mut self, ptr: *mut u8) -> bool {
        if self.len >= self.limit {
            return false;
        }
        write_bytes(ptr, 0, self.size);
        let node = ptr as *mut FreeNode;
        (*node).next = self.head;
        self.head = node;
        self.len += 1;
        true
    }
}

impl CacheKind {
    fn on_alloc_hit(&self) {
        match self {
            CacheKind::Tcb => TCB_ALLOC_HIT.fetch_add(1, Ordering::Relaxed),
            CacheKind::Inode => INODE_ALLOC_HIT.fetch_add(1, Ordering::Relaxed),
        };
    }

    fn on_alloc_miss(&self) {
        match self {
            CacheKind::Tcb => TCB_ALLOC_MISS.fetch_add(1, Ordering::Relaxed),
            CacheKind::Inode => INODE_ALLOC_MISS.fetch_add(1, Ordering::Relaxed),
        };
    }

    fn on_recycle_hit(&self) {
        match self {
            CacheKind::Tcb => TCB_RECYCLE_HIT.fetch_add(1, Ordering::Relaxed),
            CacheKind::Inode => INODE_RECYCLE_HIT.fetch_add(1, Ordering::Relaxed),
        };
    }

