/// Pending signal queue with Linux-like rule:
/// - 标准信号去重（同一 signo 仅保留一个挂起实例）
/// - 实时信号可排队
#[derive(Clone)]
pub(crate) struct SignalMsgQueue {
    pending_std: VecDeque<SigInfo>,
    pending_rt: BTreeMap<usize, VecDeque<SigInfo>>,
    pending_std_bitmap: SigSet,
}

impl Default for SignalMsgQueue {
    fn default() -> Self {
        Self {
            pending_std: VecDeque::new(),
            pending_rt: BTreeMap::new(),
            pending_std_bitmap: SigSet::empty(),
        }
    }
}

impl SignalMsgQueue {
    fn pop_std_if(&mut self, mut pred: impl FnMut(usize) -> bool) -> Option<SigInfo> {
        let n = self.pending_std.len();
        for _ in 0..n {
            let info = self.pending_std.pop_front()?;
            let signo = info.si_signo;
            if pred(signo) {
                self.pending_std_bitmap.remove_sig(signo);
                return Some(info);
            }
            self.pending_std.push_back(info);
        }
        None
    }

    fn pop_rt_if(&mut self, mut pred: impl FnMut(usize) -> bool) -> Option<SigInfo> {
        for (&signo, q) in self.pending_rt.iter_mut() {
            if !pred(signo) {
                continue;
            }
            if let Some(info) = q.pop_front() {
                return Some(info);
            }
        }
        None
    }

    /// Create an empty pending signal queue.
    pub(crate) fn new() -> Self {
        Self::default()
    }

    /// Push one signal message into pending queue.
    pub(crate) fn push(&mut self, info: SigInfo) {
        let signo = info.si_signo;
        if !(1..=SIGRTMAX).contains(&signo) {
            return;
        }
        if signo < SIGRTMIN {
            if !self.pending_std_bitmap.contain_sig(signo) {
                self.pending_std_bitmap.add_sig(signo);
                self.pending_std.push_back(info);
            }
            return;

